"use client";

import { useState, useEffect } from "react";
import { Plus, Search, Filter, FileText, Loader2, X } from "lucide-react";
import { db } from "@/lib/firebase";
import { collection, onSnapshot, query, orderBy, addDoc, serverTimestamp } from "firebase/firestore";

interface Transaccion {
  id: string;
  tipo: "acta" | "gasto";
  concepto: string;
  especialista: string;
  monto: number;
  estado: string;
  fechaString: string;
  creadoAt: any;
}

export default function ActasGastosPage() {
  const [activeTab, setActiveTab] = useState<"actas" | "gastos">("actas");
  const [transacciones, setTransacciones] = useState<Transaccion[]>([]);
  const [cargando, setCargando] = useState(true);
  const [modalAbierto, setModalAbierto] = useState(false);
  const [nuevaData, setNuevaData] = useState({ concepto: "", especialista: "", monto: 0 });
  const [isSubmitting, setIsSubmitting] = useState(false);

  useEffect(() => {
    const q = query(collection(db, "transacciones"), orderBy("creadoAt", "desc"));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const datos = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      })) as Transaccion[];
      setTransacciones(datos);
      setCargando(false);
    });

    return () => unsubscribe();
  }, []);

  const handleCrearRegistro = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    try {
      await addDoc(collection(db, "transacciones"), {
        tipo: activeTab,
        concepto: nuevaData.concepto,
        especialista: activeTab === "actas" ? nuevaData.especialista : "Operativo",
        monto: Number(nuevaData.monto),
        estado: "Pagado",
        fechaString: new Date().toLocaleTimeString("es-ES", { hour: "2-digit", minute: "2-digit" }),
        creadoAt: serverTimestamp(),
      });
      setModalAbierto(false);
      setNuevaData({ concepto: "", especialista: "", monto: 0 });
    } catch (error) {
      console.error(error);
    } finally {
      setIsSubmitting(false);
    }
  };

  const datosFiltrados = transacciones.filter(
    (t) => (t.tipo + "s") === activeTab
  );

  return (
    <div className="space-y-8">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-4 animate-fade-in-up stagger-1">
        <div>
          <h1 className="font-display text-4xl text-text-primary tracking-wide">
            GESTIÓN DE <span className="text-surgical-red italic">ACTAS Y GASTOS</span>
          </h1>
          <p className="text-text-muted mt-2 text-sm leading-relaxed max-w-xl">
            Registra y administra los egresos operativos (Gastos) y los pagos por
            servicios realizados por los especialistas (Actas).
          </p>
        </div>

        <div className="flex gap-3">
          <button 
            onClick={() => setModalAbierto(true)}
            className="btn-surgical shrink-0 text-sm py-2.5 flex items-center gap-2"
          >
            <Plus size={16} />
            <span>Nuevo Registro</span>
          </button>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex border-b border-outline animate-fade-in-up stagger-2">
        <button
          onClick={() => setActiveTab("actas")}
          className={`px-8 py-4 font-display text-xl transition-all ${
            activeTab === "actas"
              ? "text-surgical-red border-b-2 border-surgical-red bg-surgical-red/5"
              : "text-text-secondary hover:text-white"
          }`}
        >
          Actas (Servicios)
        </button>
        <button
          onClick={() => setActiveTab("gastos")}
          className={`px-8 py-4 font-display text-xl transition-all ${
            activeTab === "gastos"
              ? "text-surgical-red border-b-2 border-surgical-red bg-surgical-red/5"
              : "text-text-secondary hover:text-white"
          }`}
        >
          Gastos (Operacionales)
        </button>
      </div>

      {/* Data Table Area */}
      <div className="glass-card overflow-hidden animate-fade-in-up stagger-3">
        <div className="overflow-x-auto min-h-[300px]">
          {cargando ? (
            <div className="flex flex-col items-center justify-center p-20 text-text-muted">
              <Loader2 size={32} className="animate-spin text-surgical-red mb-4" />
              <p className="text-sm tracking-widest uppercase">Cargando registros...</p>
            </div>
          ) : datosFiltrados.length === 0 ? (
            <div className="flex flex-col items-center justify-center p-20 text-text-muted">
              <FileText size={48} className="text-surface-bright mb-4" />
              <p className="text-sm tracking-widest uppercase">No hay registros de {activeTab}</p>
            </div>
          ) : (
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-surface-high border-b border-outline text-text-muted text-xs uppercase tracking-widest">
                  <th className="p-4 font-medium">ID / Ref</th>
                  <th className="p-4 font-medium">Hora</th>
                  <th className="p-4 font-medium">Concepto</th>
                  <th className="p-4 font-medium">Responsable</th>
                  <th className="p-4 font-medium text-right">Monto</th>
                  <th className="p-4 font-medium text-center">Estado</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-outline">
                {datosFiltrados.map((t, i) => (
                  <tr key={t.id} className="hover:bg-surface-high/50 transition-colors group cursor-pointer">
                    <td className="p-4">
                      <div className="flex items-center gap-3">
                        <div className={`w-8 h-8 rounded flex items-center justify-center transition-colors
                          ${activeTab === 'actas' ? 'bg-green-500/10 text-green-500 group-hover:bg-green-500 group-hover:text-white' : 'bg-red-500/10 text-red-500 group-hover:bg-red-500 group-hover:text-white'}`}>
                          <FileText size={14} />
                        </div>
                        <span className="text-sm font-medium">#{t.id.slice(0,6).toUpperCase()}</span>
                      </div>
                    </td>
                    <td className="p-4 text-sm text-text-secondary">{t.fechaString}</td>
                    <td className="p-4 text-sm">{t.concepto}</td>
                    <td className="p-4 text-sm">{t.especialista}</td>
                    <td className={`p-4 font-display text-lg text-right ${activeTab === 'actas' ? 'text-green-500' : 'text-red-500'}`}>
                      ${t.monto.toFixed(2)}
                    </td>
                    <td className="p-4 text-center">
                      <span className="inline-flex items-center gap-1.5 px-2.5 py-1 text-[10px] font-bold tracking-widest uppercase rounded-full bg-green-500/10 text-green-500 border border-green-500/20 shadow-[0_0_10px_rgba(34,197,94,0.1)]">
                        <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse" />
                        {t.estado}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>

      {/* Modal Nuevo Registro */}
      {modalAbierto && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-void/80 backdrop-blur-sm">
          <div className="glass-card w-full max-w-md p-6 relative border-t-2 border-t-surgical-red">
            <button 
              onClick={() => setModalAbierto(false)} 
              className="absolute top-4 right-4 text-text-muted hover:text-white transition-colors"
            >
              <X size={20} />
            </button>

            <h3 className="font-display text-3xl mb-6">
              NUEVO <span className="text-surgical-red italic">{activeTab.toUpperCase()}</span>
            </h3>

            <form onSubmit={handleCrearRegistro} className="space-y-4">
              <div>
                <label className="block text-xs uppercase tracking-widest text-text-secondary mb-2">Concepto</label>
                <input 
                  type="text" 
                  required 
                  className="input-surgical"
                  placeholder={activeTab === 'actas' ? 'Corte de Cabello' : 'Insumos de limpieza'}
                  value={nuevaData.concepto}
                  onChange={e => setNuevaData({...nuevaData, concepto: e.target.value})}
                />
              </div>

              {activeTab === "actas" && (
                <div>
                  <label className="block text-xs uppercase tracking-widest text-text-secondary mb-2">Responsable / Especialista</label>
                  <select 
                    required 
                    className="input-surgical"
                    value={nuevaData.especialista}
                    onChange={e => setNuevaData({...nuevaData, especialista: e.target.value})}
                  >
                    <option value="" className="bg-surface-high">Selecciona un barbero</option>
                    <option value="Eduardo" className="bg-surface-high">Eduardo</option>
                    <option value="Franyer" className="bg-surface-high">Franyer</option>
                    <option value="Brayan" className="bg-surface-high">Brayan</option>
                  </select>
                </div>
              )}

              <div>
                <label className="block text-xs uppercase tracking-widest text-text-secondary mb-2">Monto ($)</label>
                <input 
                  type="number" 
                  step="0.01" 
                  required 
                  className="input-surgical"
                  placeholder="0.00"
                  value={nuevaData.monto || ''}
                  onChange={e => setNuevaData({...nuevaData, monto: Number(e.target.value)})}
                />
              </div>

              <div className="pt-4 flex gap-3">
                <button 
                  type="button" 
                  onClick={() => setModalAbierto(false)}
                  className="w-full py-3 rounded-xl border border-outline text-text-muted hover:text-white transition-colors uppercase tracking-widest text-xs font-bold"
                >
                  Cancelar
                </button>
                <button 
                  type="submit" 
                  disabled={isSubmitting}
                  className="w-full btn-surgical py-3 flex justify-center items-center uppercase tracking-widest text-xs font-bold disabled:opacity-50"
                >
                  {isSubmitting ? <Loader2 size={16} className="animate-spin" /> : "Guardar"}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { useAuth } from "@/context/AuthContext";
import { SERVICES, BARBERS } from "@/lib/types";
import { 
  collection, 
  addDoc, 
  onSnapshot,
  query,
  orderBy,
  where
} from "firebase/firestore";
import { db } from "@/lib/firebase";
import { Calendar, Clock, User, Plus, ChevronLeft, ChevronRight, X, Check } from "lucide-react";

const TIME_SLOTS = [
  "09:00", "09:45", "10:30", "11:15", "12:00", "12:45", 
  "13:30", "14:15", "15:00", "15:45", "16:30", "17:15", "18:00"
];

interface BlockedTime {
  id: string;
  barberId: string;
  date: string;
  time: string;
}

export default function CitasPage() {
  const { userRole } = useAuth();
  const isAdmin = userRole?.role === "admin";
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [blockedTimes, setBlockedTimes] = useState<BlockedTime[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [formData, setFormData] = useState({ barberId: "", serviceId: "", clientName: "", clientPhone: "", time: "" });

  useEffect(() => {
    let q;
    if (isAdmin) {
      q = query(collection(db, "blocked_times"), orderBy("date", "desc"));
    } else {
      q = query(collection(db, "blocked_times"), where("barberId", "==", userRole?.uid), orderBy("date", "desc"));
    }

    const unsubscribe = onSnapshot(q, (snapshot) => {
      const data = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      })) as BlockedTime[];
      setBlockedTimes(data);
    });
    return () => unsubscribe();
  }, [isAdmin, userRole?.uid]);

  const getDaysInMonth = (date: Date) => {
    const year = date.getFullYear();
    const month = date.getMonth();
    const firstDay = new Date(year, month, 1);
    const lastDay = new Date(year, month + 1, 0);
    const days = [];

    const startPadding = firstDay.getDay();
    for (let i = 0; i < startPadding; i++) {
      days.push(new Date(year, month, -startPadding + i + 1));
    }

    for (let i = 1; i <= lastDay.getDate(); i++) {
      days.push(new Date(year, month, i));
    }

    const endPadding = 42 - days.length;
    for (let i = 1; i <= endPadding; i++) {
      days.push(new Date(year, month + 1, i));
    }

    return days;
  };

  const days = getDaysInMonth(currentDate);
  const monthNames = ["Enero", "Febrero", "Marzo", "Abril", "Mayo", "Junio", "Julio", "Agosto", "Septiembre", "Octubre", "Noviembre", "Diciembre"];

  const isBlocked = (date: Date, time: string) => {
    const dateStr = date.toISOString().split("T")[0];
    return blockedTimes.some(bt => bt.date === dateStr && bt.time === time && (isAdmin || bt.barberId === userRole?.uid));
  };

  const handlePrevMonth = () => {
    setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1));
  };

  const handleNextMonth = () => {
    setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1));
  };

  const handleBlockTime = async (e: React.FormEvent) => {
    e.preventDefault();
    await addDoc(collection(db, "blocked_times"), {
      barberId: userRole?.uid,
      date: selectedDate.toISOString().split("T")[0],
      time: formData.time,
      createdAt: new Date()
    });
    setIsModalOpen(false);
    setFormData({ ...formData, time: "" });
  };

  const handleCancelBlock = async (id: string) => {
    await import("firebase/firestore").then(({ deleteDoc, doc }) => 
      deleteDoc(doc(db, "blocked_times", id))
    );
  };

  return (
    <div className="space-y-6">
      <div>
        <h1 className="font-display text-3xl text-white tracking-wide">Citas</h1>
        <p className="text-text-secondary mt-1">Gestiona tu calendario y horarios bloqueados</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 glass-card p-6">
          <div className="flex items-center justify-between mb-6">
            <button onClick={handlePrevMonth} className="p-2 hover:bg-surface-high rounded-lg transition-colors">
              <ChevronLeft className="text-text-secondary" />
            </button>
            <h2 className="font-display text-xl text-white">
              {monthNames[currentDate.getMonth()]} {currentDate.getFullYear()}
            </h2>
            <button onClick={handleNextMonth} className="p-2 hover:bg-surface-high rounded-lg transition-colors">
              <ChevronRight className="text-text-secondary" />
            </button>
          </div>

          <div className="grid grid-cols-7 gap-1">
            {["Dom", "Lun", "Mar", "Mié", "Jue", "Vie", "Sáb"].map(day => (
              <div key={day} className="text-center text-xs text-text-muted uppercase py-2">{day}</div>
            ))}
            {days.map((day, i) => {
              const isToday = day.toDateString() === new Date().toDateString();
              const isCurrentMonth = day.getMonth() === currentDate.getMonth();
              const isSelected = day.toDateString() === selectedDate.toDateString();

              return (
                <button
                  key={i}
                  onClick={() => setSelectedDate(day)}
                  className={`
                    p-2 text-sm rounded-lg transition-all
                    ${!isCurrentMonth ? "text-text-muted/30" : ""}
                    ${isSelected ? "bg-surgical-red text-white" : "hover:bg-surface-high"}
                    ${isToday && !isSelected ? "border border-surgical-red" : ""}
                  `}
                >
                  {day.getDate()}
                </button>
              );
            })}
          </div>
        </div>

        <div className="glass-card p-6">
          <h3 className="font-display text-xl text-white mb-4">
            {selectedDate.toLocaleDateString("es-ES", { weekday: "long", day: "numeric", month: "long" })}
          </h3>

          <div className="space-y-2 mb-6">
            <p className="text-text-secondary text-sm">Horarios disponibles</p>
            <div className="grid grid-cols-3 gap-2">
              {TIME_SLOTS.map(time => {
                const blocked = isBlocked(selectedDate, time);
                return (
                  <button
                    key={time}
                    onClick={() => !blocked && setFormData({ ...formData, time, barberId: userRole?.uid || "", serviceId: "", clientName: "", clientPhone: "" }) && setIsModalOpen(true)}
                    disabled={blocked}
                    className={`
                      px-2 py-2 text-xs rounded-lg transition-all
                      ${blocked ? "bg-red-500/20 text-red-500 cursor-not-allowed" : "bg-surface-high text-text-secondary hover:text-white hover:bg-surgical-red/20"}
                    `}
                  >
                    {time}
                  </button>
                );
              })}
            </div>
          </div>

          <div className="border-t border-outline pt-4">
            <p className="text-text-secondary text-sm mb-3">Horarios bloqueados</p>
            <div className="space-y-2">
              {blockedTimes
                .filter(bt => bt.date === selectedDate.toISOString().split("T")[0] && (isAdmin || bt.barberId === userRole?.uid))
                .map(bt => (
                  <div key={bt.id} className="flex items-center justify-between bg-red-500/10 p-3 rounded-lg">
                    <span className="text-red-400 text-sm">{bt.time}</span>
                    <button onClick={() => handleCancelBlock(bt.id)} className="text-text-muted hover:text-red-500">
                      <X size={16} />
                    </button>
                  </div>
                ))}
              {blockedTimes.filter(bt => bt.date === selectedDate.toISOString().split("T")[0]).length === 0 && (
                <p className="text-text-muted text-sm">No hay horarios bloqueados</p>
              )}
            </div>
          </div>
        </div>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-void/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="glass-card p-8 w-full max-w-md">
            <h2 className="font-display text-2xl text-white mb-6">Bloquear Horario</h2>
            <form onSubmit={handleBlockTime} className="space-y-4">
              <div>
                <label className="block text-xs text-text-secondary uppercase tracking-wider mb-2">Hora</label>
                <input 
                  type="text"
                  className="input-surgical bg-transparent w-full"
                  value={formData.time}
                  disabled
                />
              </div>
              <div>
                <label className="block text-xs text-text-secondary uppercase tracking-wider mb-2">Fecha</label>
                <input 
                  type="text"
                  className="input-surgical bg-transparent w-full"
                  value={selectedDate.toLocaleDateString("es-ES")}
                  disabled
                />
              </div>
              <div className="flex gap-4 mt-6">
                <button 
                  type="button" 
                  onClick={() => setIsModalOpen(false)}
                  className="flex-1 px-4 py-3 rounded-xl border border-outline text-text-secondary hover:bg-surface-high transition-colors"
                >
                  Cancelar
                </button>
                <button 
                  type="submit" 
                  className="flex-1 btn-surgical flex items-center justify-center gap-2"
                >
                  <Check size={18} /> Bloquear
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { useAuth } from "@/context/AuthContext";
import { type Client } from "@/lib/types";
import { 
  collection, 
  addDoc, 
  updateDoc, 
  deleteDoc, 
  doc, 
  onSnapshot,
  query,
  orderBy,
  where
} from "firebase/firestore";
import { db } from "@/lib/firebase";
import { Plus, Pencil, Trash2, Phone, Mail, User, Check, Search } from "lucide-react";

export default function ClientesPage() {
  const { userRole } = useAuth();
  const [clientes, setClientes] = useState<Client[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState("");
  const [formData, setFormData] = useState({ name: "", phone: "", email: "", notes: "" });

  useEffect(() => {
    let q;
    if (userRole?.role === "admin") {
      q = query(collection(db, "clients"), orderBy("name"));
    } else {
      q = query(collection(db, "clients"), where("createdBy", "==", userRole?.uid), orderBy("name"));
    }

    const unsubscribe = onSnapshot(q, (snapshot) => {
      const data = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data(),
        createdAt: doc.data().createdAt?.toDate()
      })) as Client[];
      setClientes(data);
    });
    return () => unsubscribe();
  }, [userRole?.role, userRole?.uid]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const clientData = {
      ...formData,
      createdAt: new Date(),
      createdBy: userRole?.uid || ""
    };

    if (editingId) {
      await updateDoc(doc(db, "clients", editingId), formData);
    } else {
      await addDoc(collection(db, "clients"), clientData);
    }
    setIsModalOpen(false);
    setEditingId(null);
    setFormData({ name: "", phone: "", email: "", notes: "" });
  };

  const handleEdit = (cliente: Client) => {
    setFormData({ name: cliente.name, phone: cliente.phone, email: cliente.email || "", notes: cliente.notes || "" });
    setEditingId(cliente.id);
    setIsModalOpen(true);
  };

  const handleDelete = async (id: string) => {
    if (confirm("¿Eliminar este cliente?")) {
      await deleteDoc(doc(db, "clients", id));
    }
  };

  const filteredClientes = clientes.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    c.phone.includes(searchTerm)
  );

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="font-display text-3xl text-white tracking-wide">Clientes</h1>
          <p className="text-text-secondary mt-1">Gestiona los clientes de la barbería</p>
        </div>
        <button 
          onClick={() => { setIsModalOpen(true); setEditingId(null); setFormData({ name: "", phone: "", email: "", notes: "" }); }}
          className="btn-surgical flex items-center gap-2"
        >
          <Plus size={18} /> Nuevo Cliente
        </button>
      </div>

      <div className="relative">
        <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-text-muted" size={18} />
        <input 
          type="text"
          placeholder="Buscar por nombre o teléfono..."
          className="input-surgical bg-surface pl-12 w-full"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      <div className="overflow-x-auto">
        <table className="w-full">
          <thead>
            <tr className="border-b border-outline">
              <th className="text-left py-4 px-4 text-xs text-text-muted uppercase tracking-wider font-medium">Cliente</th>
              <th className="text-left py-4 px-4 text-xs text-text-muted uppercase tracking-wider font-medium">Teléfono</th>
              <th className="text-left py-4 px-4 text-xs text-text-muted uppercase tracking-wider font-medium">Email</th>
              <th className="text-left py-4 px-4 text-xs text-text-muted uppercase tracking-wider font-medium">Notas</th>
              <th className="text-right py-4 px-4 text-xs text-text-muted uppercase tracking-wider font-medium">Acciones</th>
            </tr>
          </thead>
          <tbody>
            {filteredClientes.map((cliente) => (
              <tr key={cliente.id} className="border-b border-white/5 hover:bg-surface-high/30 transition-colors">
                <td className="py-4 px-4">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-full bg-surgical-red/20 flex items-center justify-center">
                      <User size={18} className="text-surgical-red" />
                    </div>
                    <span className="font-medium text-white">{cliente.name}</span>
                  </div>
                </td>
                <td className="py-4 px-4 text-text-secondary">{cliente.phone}</td>
                <td className="py-4 px-4 text-text-secondary">{cliente.email || "-"}</td>
                <td className="py-4 px-4 text-text-secondary max-w-xs truncate">{cliente.notes || "-"}</td>
                <td className="py-4 px-4">
                  <div className="flex items-center justify-end gap-2">
                    <button onClick={() => handleEdit(cliente)} className="p-2 text-text-muted hover:text-surgical-red transition-colors">
                      <Pencil size={16} />
                    </button>
                    <button onClick={() => handleDelete(cliente.id)} className="p-2 text-text-muted hover:text-surgical-red transition-colors">
                      <Trash2 size={16} />
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        {filteredClientes.length === 0 && (
          <div className="text-center py-12 text-text-muted">
            No hay clientes registrados
          </div>
        )}
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-void/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="glass-card p-8 w-full max-w-md">
            <h2 className="font-display text-2xl text-white mb-6">
              {editingId ? "Editar Cliente" : "Nuevo Cliente"}
            </h2>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-xs text-text-secondary uppercase tracking-wider mb-2">Nombre</label>
                <input 
                  type="text" 
                  className="input-surgical bg-transparent w-full"
                  placeholder="Juan Pérez"
                  value={formData.name}
                  onChange={(e) => setFormData({ ...formData, name: e.target.value })}
