                    <option value="">Barbería (General)</option>
                    {BARBERS.map(barber => (
                      <option key={barber.uid} value={barber.uid}>{barber.name}</option>
                    ))}
                  </select>
                </div>
              )}

              <div>
                <label className="block text-xs text-text-secondary uppercase tracking-wider mb-2">Monto Objetivo ($)</label>
                <input 
                  type="number" 
